def cat(lines):
    return lines

def mapper(lines):
    pairs = []
    for line in lines:
        for vowel in 'aeiou':
            count = line.count(vowel)
            if count > 0:
                pairs.append((vowel, count))
    return pairs

def sort_pairs(pairs):
    return sorted(pairs)

def reducer(sorted_pairs):
    totals = {}
    for key, value in sorted_pairs:
        if key not in totals:
            totals[key] = 0
        totals[key] = totals[key] + value
    return totals

haiku = ['Google MapReduce', 'Is a Big Data framework', 'For batch processing']
stage1 = cat(haiku)
stage2 = mapper(stage1)
stage3 = sort_pairs(stage2)
stage4 = reducer(stage3)
print(stage4)
